import{_ as e,o as t,c as i,ag as n}from"./chunks/framework.DTiDeF2Q.js";const g=JSON.parse('{"title":"Alias Configuration | Dotfiles (ID)","titleTemplate":":title","description":"Alias shell untuk Bash dan Zsh yang langsung membuka file konfigurasi shell, Git, SSH, dan server. Kompatibel dengan macOS, Linux, dan WSL melalui Dotfiles.","frontmatter":{"title":"Alias Configuration | Dotfiles","description":"Alias shell untuk Bash dan Zsh yang langsung membuka file konfigurasi shell, Git, SSH, dan server. Kompatibel dengan macOS, Linux, dan WSL melalui Dotfiles.","lang":"id-ID","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Alias Configuration preview","canonical":"/id/aliases/configuration/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Alias Configuration","pageType":"docs","schemaType":"WebPage","metaTitle":"Alias Configuration - Dotfiles (ID)","permalink":"/id/aliases/configuration/","sidebar":true,"meta":[{"name":"keywords","content":"configuration aliases, shell config, dotfiles, bash aliases, zsh aliases, git config, ssh config"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Alias Configuration - Dotfiles"},{"name":"twitter:description","content":"Alias shell yang langsung membuka file konfigurasi shell, Git, SSH, dan server."},{"name":"og:title","content":"Alias Configuration - Dotfiles"},{"name":"og:description","content":"Alias shell yang langsung membuka file konfigurasi shell, Git, SSH, dan server."},{"name":"og:image:alt","content":"Dotfiles - Dirancang sederhana untuk menyesuaikan kehidupan shell Anda"},{"name":"og:locale","content":"id_ID"}]},"headers":[],"relativePath":"id/aliases/configuration/index.md","filePath":"id/aliases/configuration/index.md","lastUpdated":1773010926000}'),o={name:"id/aliases/configuration/index.md"};function r(s,a,d,l,h,u){return t(),i("div",null,[...a[0]||(a[0]=[n('<h1 id="alias-configuration" tabindex="-1">Alias Configuration <a class="header-anchor" href="#alias-configuration" aria-label="Permalink to &quot;Alias Configuration&quot;">​</a></h1><p>Buka file konfigurasi di editor default dengan satu perintah.</p><h2 id="ikhtisar" tabindex="-1">Ikhtisar <a class="header-anchor" href="#ikhtisar" aria-label="Permalink to &quot;Ikhtisar&quot;">​</a></h2><p>Alias Configuration menyediakan pintasan untuk membuka file konfigurasi yang sering diedit. Alias ini didefinisikan di <code>configuration.aliases.sh</code> dan dimuat secara otomatis oleh chezmoi.</p><p>Setiap alias meluncurkan file yang sesuai di editor teks default sistem, menghilangkan kebutuhan untuk mengingat path file atau mengetik perintah panjang.</p><h2 id="referensi" tabindex="-1">Referensi <a class="header-anchor" href="#referensi" aria-label="Permalink to &quot;Referensi&quot;">​</a></h2><h3 id="konfigurasi-shell" tabindex="-1">Konfigurasi Shell <a class="header-anchor" href="#konfigurasi-shell" aria-label="Permalink to &quot;Konfigurasi Shell&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Deskripsi</th></tr></thead><tbody><tr><td><code>bshrc</code></td><td>Buka file konfigurasi Bash (~/.bashrc)</td></tr><tr><td><code>bshp</code></td><td>Buka profil Bash (~/.bash_profile)</td></tr><tr><td><code>zshrc</code></td><td>Buka file konfigurasi Zsh (~/.zshrc)</td></tr><tr><td><code>zshp</code></td><td>Buka profil Zsh (~/.zprofile)</td></tr></tbody></table><h3 id="kontrol-versi" tabindex="-1">Kontrol Versi <a class="header-anchor" href="#kontrol-versi" aria-label="Permalink to &quot;Kontrol Versi&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Deskripsi</th></tr></thead><tbody><tr><td><code>gcfg</code></td><td>Buka file konfigurasi Git (~/.gitconfig)</td></tr><tr><td><code>gign</code></td><td>Buka file Gitignore (~/.gitignore)</td></tr></tbody></table><h3 id="jaringan-dan-server" tabindex="-1">Jaringan dan Server <a class="header-anchor" href="#jaringan-dan-server" aria-label="Permalink to &quot;Jaringan dan Server&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Deskripsi</th></tr></thead><tbody><tr><td><code>apconf</code></td><td>Buka file konfigurasi Apache</td></tr><tr><td><code>ngconf</code></td><td>Buka file konfigurasi Nginx</td></tr><tr><td><code>sshconf</code></td><td>Buka file konfigurasi SSH (~/.ssh/config)</td></tr><tr><td><code>hosts</code></td><td>Buka file hosts (/etc/hosts)</td></tr></tbody></table><h3 id="alat-pengembangan" tabindex="-1">Alat Pengembangan <a class="header-anchor" href="#alat-pengembangan" aria-label="Permalink to &quot;Alat Pengembangan&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Deskripsi</th></tr></thead><tbody><tr><td><code>dockcomp</code></td><td>Buka file Docker Compose</td></tr><tr><td><code>eddir</code></td><td>Buka direktori saat ini di editor default</td></tr></tbody></table>',14)])])}const f=e(o,[["render",r]]);export{g as __pageData,f as default};
